mapper.select:


     and user_id = #{userId}
     and account = #{account}
     and week_start_time = #{weekStartTime}
     and week_end_time = #{weekEndTime}
     and settle_status = #{settleStatus}
     and batch_no = #{batchNo}
     and create_time between #{params.beginCreateTime} and #{params.endCreateTime}
    and deleted = 0

order by week_start_time desc, id desc

select ifnull(sum(case
    when o.performance_start_time between #{weekStartTime} and #{weekEndTime}
        then ifnull(o.performance_points, ifnull(o.stake_usdt_amount, 0) * ifnull(o.performance_coefficient, 1))
    else 0 end), 0)
- ifnull(sum(case
    when o.performance_end_time between #{weekStartTime} and #{weekEndTime}
        then ifnull(o.performance_points, ifnull(o.stake_usdt_amount, 0) * ifnull(o.performance_coefficient, 1))
    else 0 end), 0)
from t_stake_hosting_order o
where o.deleted = 0
  and o.pay_status in (1, 2)
  and o.user_id = #{userId}
  and (
      o.performance_start_time between #{weekStartTime} and #{weekEndTime}
      or o.performance_end_time between #{weekStartTime} and #{weekEndTime}
  )

select ifnull(sum(case
    when o.performance_start_time between #{weekStartTime} and #{weekEndTime}
        then ifnull(o.performance_points, ifnull(o.stake_usdt_amount, 0) * ifnull(o.performance_coefficient, 1))
    else 0 end), 0)
- ifnull(sum(case
    when o.performance_end_time between #{weekStartTime} and #{weekEndTime}
        then ifnull(o.performance_points, ifnull(o.stake_usdt_amount, 0) * ifnull(o.performance_coefficient, 1))
    else 0 end), 0)
from t_stake_hosting_order o
inner join t_user_relation r on r.pos_user_id = o.user_id
    and r.par_user_id = #{userId}
    and r.distance > 0
    and r.active_flag = 1
where o.deleted = 0
  and o.pay_status in (1, 2)
  and (
      o.performance_start_time between #{weekStartTime} and #{weekEndTime}
      or o.performance_end_time between #{weekStartTime} and #{weekEndTime}
  )

select ifnull(sum(ifnull(o.performance_points, ifnull(o.stake_usdt_amount, 0) * ifnull(o.performance_coefficient, 1))), 0)
from t_stake_hosting_order o
where o.deleted = 0
  and o.pay_status in (1, 2)
  and o.performance_start_time is not null
  and o.performance_end_time is not null
  and o.performance_start_time <= #{snapshotTime}
  and o.performance_end_time > #{snapshotTime}
  and (
      o.user_id = #{directUserId}
      or exists (
          select 1
          from t_user_relation r
          where r.par_user_id = #{directUserId}
            and r.pos_user_id = o.user_id
            and r.distance > 0
            and r.active_flag = 1
      )
  )


where deleted = 0
  and week_start_time = #{weekStartTime}

      and user_id in

          #{userId}



      and 1 = 0
